import { Pallet } from '@/hooks/usePallets';
import { 
  LabelDimensions, 
  DEFAULT_LABEL_SIZE, 
  mmToZplDots, 
  calculatePalletLabelPositions,
  getScaleFactor,
  scaleFontSize,
  getLabelDimensionsDots
} from './labelScaling';

export interface PalletLabelData {
  pallet: Pallet;
  labels: Array<{
    sku: string;
    quantity: number;
    boxes: number;
  }>;
}

export const generatePalletZPL = (data: PalletLabelData, labelSize?: LabelDimensions): string => {
  const { pallet, labels } = data;
  
  // Use provided dimensions or default
  const dimensions = labelSize || DEFAULT_LABEL_SIZE;
  const dims = getLabelDimensionsDots(dimensions);
  const positions = calculatePalletLabelPositions(dimensions);
  const scale = getScaleFactor(dimensions);
  
  // Calculate totals
  const totalBoxes = labels.reduce((sum, l) => sum + l.boxes, 0);
  const totalUnits = labels.reduce((sum, l) => sum + l.quantity, 0);
  
  // Calculate font sizes based on scale
  const customerFontSize = scaleFontSize(48, dimensions);
  const poFontSize = scaleFontSize(24, dimensions);
  const skuFontSize = scaleFontSize(64, dimensions);
  const skuDetailFontSize = scaleFontSize(24, dimensions);
  const totalUnitsFontSize = scaleFontSize(72, dimensions);
  const totalBoxesFontSize = scaleFontSize(48, dimensions);
  
  // Calculate positions
  const logoX = positions.logo.x;
  const logoY = positions.logo.y;
  const customerY = positions.customer.y;
  const poY = positions.po.y;
  const skuStartY = positions.skuSection.y;
  const totalUnitsY = positions.totalUnits.y;
  const totalBoxesY = positions.totalBoxes.y;
  const qrX = positions.qrCode.x;
  const qrY = positions.qrCode.y;
  const qrMag = Math.max(2, Math.round(positions.qrCode.width || 5));
  
  // Field block width
  const fieldBlockWidth = dims.widthDots - 30;
  
  // SKU line spacing based on scale
  const skuLineSpacing = Math.round(80 * scale);
  const skuDetailOffset = Math.round(40 * scale);
  
  // Create SKU summary lines - only show 2 SKUs to match preview, larger text, centered
  let skuLines = '';
  if (labels.length > 0) {
    labels.slice(0, 2).forEach((label, index) => {
      const yPos = skuStartY + (index * skuLineSpacing);
      skuLines += `^FO0,${yPos}^FB${dims.widthDots},1,0,C,0^A0N,${skuFontSize},${skuFontSize}^FD${label.sku}^FS\n`;
      skuLines += `^FO0,${yPos + skuDetailOffset}^FB${dims.widthDots},1,0,C,0^A0,${skuDetailFontSize},${skuDetailFontSize}^FD${label.boxes} boxes (${label.quantity} units)^FS\n`;
    });
    
    // Add "more SKUs" line if needed
    if (labels.length > 2) {
      const moreSkusY = skuStartY + (2 * skuLineSpacing);
      skuLines += `^FO0,${moreSkusY}^FB${dims.widthDots},1,0,C,0^A0,${skuDetailFontSize},${skuDetailFontSize}^FD+ ${labels.length - 2} more SKUs^FS\n`;
    }
  } else {
    // No labels assigned
    const noLabelsFont = scaleFontSize(48, dimensions);
    skuLines = `^FO0,${skuStartY}^FB${dims.widthDots},1,0,C,0^A0N,${noLabelsFont},${noLabelsFont}^FDNO LABELS^FS\n^FO0,${skuStartY + Math.round(60 * scale)}^FB${dims.widthDots},1,0,C,0^A0N,${noLabelsFont},${noLabelsFont}^FDASSIGNED^FS\n`;
  }

  return `
^XA
^PW${dims.widthDots}
${companyLogoZPL(logoX, logoY)}
^FO15,${customerY}^FB${fieldBlockWidth},1,0,R,0^A0N,${customerFontSize},${customerFontSize}^FD${pallet.sku || ''}^FS
^FO15,${poY}^FB${fieldBlockWidth},1,0,R,0^A0,${poFontSize},${poFontSize}^FDPO: ${pallet.po || ''}^FS
${skuLines}
^FO0,${totalUnitsY}^FB${dims.widthDots},1,0,C,0^A0N,${totalUnitsFontSize},${totalUnitsFontSize}^FD${totalUnits} BLADES^FS
^FO0,${totalBoxesY}^FB${dims.widthDots},1,0,C,0^A0N,${totalBoxesFontSize},${totalBoxesFontSize}^FD${totalBoxes} BOXES^FS
^FO${qrX},${qrY}^BQN,2,${qrMag}^FDQA,${window.location?.origin || 'http://localhost'}/pallet-management?pallet=${pallet.id}^FS
^XZ
  `.trim();
};

